import Foundation
import AVFoundation
import SwiftUI
import Combine

// MARK: - Voice Service
//
// The spoken voice layer for the agent squad. Every agent announces
// what they're starting (open) and what they accomplished (close) at
// each heartbeat. Announcements are generated by the LLM as the first
// and last line of its response — AgentScheduler peels them off and
// routes them through this service.
//
// Design rules (from the architecture pass):
//   • One utterance speaks at a time. Concurrent announcements queue.
//   • Queue depth capped (default 3). Fourth announcement drops the oldest
//     — agents shouldn't stack up more than a few seconds of backlog.
//   • Global mute kills the queue instantly.
//   • Per-agent mute (on AgentSpec.voiceMuted) is respected at enqueue time.
//   • Quiet hours (default 22:00–07:00) silently drop announcements but
//     still log them to the flight recorder.
//   • Siri-2-ready: everything goes through AVSpeechSynthesizer, so when
//     Apple adds a .neural quality tier or new identifiers, flipping the
//     voiceIdentifier on an AgentSpec is the only change needed.
//
// Thread safety: @MainActor — all state mutations happen on the main
// thread. AVSpeechSynthesizer's delegate callbacks are marshaled back
// onto the main actor before touching state.

@MainActor
final class VoiceService: NSObject, ObservableObject {
    // MARK: Published state (UI bindings)

    /// Master mute. When true, all announcements are dropped on enqueue.
    @Published var muted: Bool = false {
        didSet {
            if muted { stopAll() }
            persist()
        }
    }

    /// Respect macOS Focus / Do Not Disturb. When true and Focus is on,
    /// only Thrawn is allowed to speak (priority agent). Everyone else is
    /// dropped with a flight-recorder log entry.
    @Published var respectFocus: Bool = true { didSet { persist() } }

    /// Quiet hours — closed range of hours (0–23). Announcements during
    /// this window are dropped. Nil means always-on.
    @Published var quietHoursStart: Int? = 22 { didSet { persist() } }
    @Published var quietHoursEnd: Int? = 7 { didSet { persist() } }

    /// Max simultaneously queued announcements. 4th+ drops oldest.
    @Published var maxQueueDepth: Int = 3 { didSet { persist() } }

    /// The agent currently speaking, for UI chrome. Nil when idle.
    @Published private(set) var currentlySpeakingAgentId: String?

    /// Snapshot of pending announcements (for the UI popover).
    @Published private(set) var pendingCount: Int = 0

    // MARK: Private state

    private let synth = AVSpeechSynthesizer()
    private var queue: [Announcement] = []
    private weak var specStore: AgentSpecStore?

    private static let settingsPath = ThrawnPaths.appSupportDir
        .appendingPathComponent("voice-settings.json")

    // MARK: - Types

    enum AnnouncementKind: String, Codable {
        case open    // first line of a heartbeat — "R2 here. Building TASK-049."
        case close   // last line on completion — "R2 out. Build clean."
        case manual  // user-initiated ("play sample") or system messages
    }

    struct Announcement: Identifiable {
        let id = UUID()
        let agentId: String
        let kind: AnnouncementKind
        let text: String
    }

    // MARK: - Init

    override init() {
        super.init()
        synth.delegate = self
        loadSettings()
    }

    /// Bind the spec store so we can resolve per-agent voice config.
    /// Also runs the voice-assignment migration: any spec whose current
    /// voiceIdentifier is nil or points at a voice that isn't installed
    /// on this machine gets auto-assigned from the preference list.
    func bind(specStore: AgentSpecStore) {
        self.specStore = specStore
        assignVoicesIfNeeded()
    }

    // MARK: - Per-agent voice preferences
    //
    // Each agent has an ordered list of AVSpeechSynthesisVoice
    // identifiers, best-first. On bind we walk the list and pick the
    // first one that resolves via AVSpeechSynthesisVoice(identifier:).
    // Rate and pitch tune the character: Boba is slow+low, Bart is fast
    // +bright, Thrawn is calm and slightly lower, C-3PO is slightly
    // faster and brighter (fussy protocol droid).
    //
    // If the user downloads new voices later, the migration will pick
    // them up on next launch only if the current assignment is invalid
    // — we don't clobber valid assignments so a future voice-picker UI
    // can override without fighting the auto-migration.

    private struct VoicePreference {
        let identifiers: [String]
        let rate: Float
        let pitch: Float
        let muted: Bool
    }

    private static let voicePreferences: [String: VoicePreference] = [
        "thrawn": VoicePreference(
